prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?modelName ?orgName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org rdfs:label ?orgName . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "fbb0") || CONTAINS(LCASE(STR(?origId)), "fbb0") || CONTAINS(LCASE(STR(?modelName)), "fbb0"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?origId ?modelName ?orgName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org rdfs:label ?orgName . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "fbb0adafe6924f58ac902063a36646fe") || 
         CONTAINS(LCASE(STR(?origId)), "fbb0adafe6924f58ac902063a36646fe") ||
         STR(?modelId) = "fbb0adafe6924f58ac902063a36646fe" ||
         STR(?origId) = "fbb0adafe6924f58ac902063a36646fe")
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName ?task ?taskName ?gateway ?gatewayType ?event ?eventName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "fbb0adafe6924f58ac902063a36646fe" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo tai:belongsTo ?defs .
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    ?task a bboExt:ChoreographyTask .
    ?task tai:belongsTo ?choreo .
    OPTIONAL { ?task bbo:name ?taskName . }
  }
  OPTIONAL {
    ?gateway a ?gatewayType .
    FILTER(?gatewayType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
    ?gateway tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?event a ?eventType .
    FILTER(?eventType IN (bboExt:StartEvent, bboExt:EndEvent, bboExt:IntermediateCatchEvent))
    ?event tai:belongsTo ?choreo .
    OPTIONAL { ?event bbo:name ?eventName . }
  }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?startEvent ?startName ?endEvent ?endName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "fbb0adafe6924f58ac902063a36646fe" .
  ?defs tai:belongsTo ?model .
  ?defs a bboExt:Definitions .
  ?choreo tai:belongsTo ?defs .
  ?choreo a bboExt:Choreography .
  OPTIONAL {
    ?startEvent a bboExt:StartEvent .
    ?startEvent tai:belongsTo ?choreo .
    OPTIONAL { ?startEvent bbo:name ?startName . }
  }
  OPTIONAL {
    ?endEvent a bboExt:EndEvent .
    ?endEvent tai:belongsTo ?choreo .
    OPTIONAL { ?endEvent bbo:name ?endName . }
  }
}
